<?php include 'header.php'; $st=$pdo->prepare('SELECT * FROM products WHERE id=?');$st->execute([$_GET['id']??0]);$p=$st->fetch(); if(!$p) die('Không tìm thấy sản phẩm'); ?>
<section class="product-detail"><div><img src="<?=$p['image']?>"></div><div><h1><?=$p['name']?></h1><p><?=$p['description']?></p><p><b>Màu:</b> <?=$p['color']?></p><p><b>Size:</b> <?=$p['sizes']?></p><h2><?php if($p['sale_price']): ?><span class="old"><?=money($p['price'])?></span> <span class="sale"><?=money($p['sale_price'])?></span><?php else: ?><?=money($p['price'])?><?php endif; ?></h2><form method="post" action="cart.php?action=add"><input type="hidden" name="id" value="<?=$p['id']?>"><label>Size</label><select name="size"><?php foreach(explode(',',$p['sizes']) as $s): ?><option><?=trim($s)?></option><?php endforeach; ?></select><label>Số lượng</label><input class="qty" type="number" name="qty" min="1" value="1"><br><br><button class="btn">Thêm vào giỏ hàng</button></form></div></section><?php include 'footer.php'; ?>
